using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=2e5+5;
struct eat
{
    int next,to,quan;
}a[MAXN];
int head[MAXN],cnt,n,m,k,d1[MAXN],d2[MAXN],d3[MAXN];
inline void add(int x,int y,int z)
{
    a[++cnt].next=head[x];
    a[cnt].to=y;
    a[cnt].quan=z;
    head[x]=cnt;
}
struct node
{
    int u,d;
    bool operator <(const node& rhs)const{
        return d>rhs.d;
    }
};
bool f[MAXN];
void dj1(int s)
{
	for(int i=1;i<=n;i++)d1[i]=inf;
    d1[s]=0;
    priority_queue<node>Q;
    Q.push((node){s,0});
    while(!Q.empty())
    {
        node ch=Q.top();
        Q.pop();
        int u=ch.u;
        int d=ch.d;
        if(d!=d1[u])continue;
        for(int i=head[u];i;i=a[i].next)
        {
            int x=a[i].to,y=a[i].quan;
            if(d1[u]+y<d1[x]){
                d1[x]=d1[u]+y;
                Q.push((node){x,d1[x]});
            }
        }
    }
}

void dj2(int s)
{
	for(int i=1;i<=n;i++)d2[i]=inf;
    d2[s]=0;
    priority_queue<node> Q;
    Q.push((node){s,0});
    while(!Q.empty())
    {
        node ch=Q.top();
        Q.pop();
        int u=ch.u;
        int d=ch.d;
        if(d!=d2[u])continue;
        for(int i=head[u];i;i=a[i].next)
        {
            int x=a[i].to,y=a[i].quan;
            if(d2[u]+y<d2[x])
            {
                d2[x]=d2[u]+y;
                Q.push((node){x,d2[x]});
            }
        }
    }
}
void dj3(int s)
{

	FOR(i,1,n)d3[i]=inf;
    d3[s]=0;
    priority_queue<node> Q;
    Q.push((node){s,0});
    while(!Q.empty())
    {
        node ch=Q.top();
        Q.pop();
        int u=ch.u,d=ch.d;
        if(d!=d3[u])continue;
        for(int i=head[u];i;i=a[i].next)
        {
            int x=a[i].to,y=a[i].quan;
            if(f[x])continue;
            if(d3[u]+y<d3[x])
            {
                d3[x]=d3[u]+y;
                Q.push((node){x,d3[x]});
            }
        }
    }
}
int main()
{
    n=read();m=read();k=read();
    FOR(i,1,k)f[read()]=1;
    FOR(i,1,m)
    {
        int a=read(),b=read(),c=read();
        add(a,b,c);
        add(b,a,c);
    }
	int x,y;
    x=read();y=read();
    dj1(1);
    dj2(x);
	dj3(1);
 	int ans=1e9;
 	ans=min(ans,d1[x]+d2[y]);
 	ans=min(ans,d1[y]+d2[y]);
 	ans=min(ans,max(d1[x],d3[y]));
 	ans=min(ans,max(d3[x],d1[y]));
 	write(ans);
    return false;
}
